1	/**
2	 * The read-only context of the running coroutine. Fetched on demand via
3	 * `io.context()` rather than threaded as a parameter, so cancellation access is
4	 * opt-in. Spawning children is not on `ctx` - use the ambient `io.*` helpers; the
5	 * scope is wired through `AsyncLocalStorage`.
6	 */
7	export interface Ctx {
8	  /** Aborts when this unit of work is cancelled. Thread into raw async (`fetch(url, { signal })`). */
9	  readonly signal: AbortSignal;
10	  /** `=== signal.aborted`. */
11	  readonly cancelled: boolean;
12	  /** Cooperative checkpoint for tight sync loops / raw promises: throws `CancelledError` if cancelled. */
13	  throwIfCancelled(): void;
14	  /** Optional label for diagnostics (zombie / unhandled-error logs). */
15	  readonly name?: string;
16	}
17	
18	export type CoroutineBody<T> = () => Promise<T>;
19	
20	export type DeferCallback = () => unknown | Promise<unknown>;
21	
22	export interface SpawnOptions {
23	  /** Budget for the body to halt after cancellation before it is reaped as a zombie. Default 5000ms. */
24	  cancelTimeout?: number;
25	  /** Total budget for the LIFO defer chain. Default 5000ms. */
26	  deferTimeout?: number;
27	}
28	
29	export type Backoff = "exponential" | "linear" | "constant";
30	
31	export interface RetryOptions {
32	  /** Total attempts (not extra retries). Default 3. */
33	  maxAttempts?: number;
34	  /** Delay growth between attempts. Default "exponential". */
35	  backoff?: Backoff;
36	  /** Delay of the first backoff step, in ms. Default 100. */
37	  baseDelayMs?: number;
38	  /** Upper bound applied to every computed delay, in ms. Default 30_000. */
39	  maxDelayMs?: number;
40	  /** Full jitter: pick a random delay in `[0, computed)`. Default true. */
41	  jitter?: boolean;
42	  /** Gate a retry on the thrown error. Default: retry every non-cancellation error. */
43	  shouldRetry?: (error: unknown, attempt: number) => boolean;
44	  /** Observe each retry just before sleeping (e.g. for logging/metrics). */
45	  onRetry?: (error: unknown, attempt: number, delayMs: number) => void;
46	}
47	
48	/**
49	 * A write-once, externally-settled awaitable. `resolve`/`reject` settle it; the
50	 * first call wins and later calls are silent no-ops. Awaiting it inside a
51	 * coroutine is cancellable via the ambient scope.
52	 */
53	export interface Future<T> extends PromiseLike<T> {
54	  /** Settle with a value. No-op if already settled. */
55	  resolve(value: T): void;
56	  /** Settle with an error. No-op if already settled. */
57	  reject(error: unknown): void;
58	  /** Whether `resolve` or `reject` has been called. */
59	  readonly settled: boolean;
60	}
61	
62	/**
63	 * A Go-style channel: a competing-consumer pipe between coroutines. Each value
64	 * is delivered to exactly one receiver. `capacity 0` is a rendezvous (every send
65	 * blocks until a receiver takes it); a positive capacity buffers that many values
66	 * before `send` blocks. All blocking ops are cancellable via the ambient scope.
67	 */
68	export interface Channel<T> extends AsyncIterable<T> {
69	  /** Send a value; blocks while the buffer is full. Rejects `ChannelClosedError` if closed. */
70	  send(value: T): Promise<void>;
71	  /** Receive the next value; blocks while empty. Rejects `ChannelClosedError` once closed and drained. */
72	  receive(): Promise<T>;
73	  /** Close the channel: future sends reject, blocked senders reject, and drained receivers complete. */
74	  close(): void;
75	  readonly closed: boolean;
76	}
77	
78	/**
79	 * A counting semaphore guarding `n` permits. `acquire` blocks (cancellably, FIFO)
80	 * until a permit is free and returns an idempotent release token; `runExclusive`
81	 * wraps acquire/release so the permit is always returned, even on throw or cancel.
82	 */
83	export interface Semaphore {
84	  /** Acquire a permit, blocking until one is free. Returns an idempotent release token. */
85	  acquire(): Promise<() => void>;
86	  /** Acquire a permit, run `fn`, and always release it afterwards. */
87	  runExclusive<T>(fn: () => T | Promise<T>): Promise<T>;
88	  /** Permits currently available. */
89	  readonly available: number;
90	}
91	
92	/** A mutual-exclusion lock: a {@link Semaphore} with a single permit. */
93	export type Mutex = Semaphore;
94	
95	/**
96	 * A Go-style wait group: a counter you `add` to and `done` from, with `wait`
97	 * resolving once it returns to zero. Driving the counter below zero throws
98	 * `WaitGroupError`. `wait` is cancellable via the ambient scope.
99	 */
100	export interface WaitGroup {
101	  /** Increase the counter by `delta` (default 1). Throws `WaitGroupError` if it would go negative. */
102	  add(delta?: number): void;
103	  /** Decrement the counter by one (`add(-1)`). */
104	  done(): void;
105	  /** Resolve once the counter is zero; blocks otherwise. */
106	  wait(): Promise<void>;
107	  /** The current counter value. */
108	  readonly count: number;
109	}
110	
111	/** An inert, one-shot, non-thenable coroutine specification. */
112	export interface Coroutine<T> {
113	  /** Start the coroutine exactly once. A second call throws `CoroutineAlreadyStartedError`. */
114	  spawn(opts?: SpawnOptions): RoutineHandle<T>;
115	}
116	
117	/** A running coroutine instance: awaitable (thenable) and cancellable. */
118	export interface RoutineHandle<T> extends PromiseLike<T> {
119	  /** Request cancellation; fire-and-forget. Idempotent. */
120	  cancel(): void;
121	  /** Request cancellation and await teardown completion. Idempotent. */
122	  cancelGracefully(opts?: { timeoutMs?: number }): Promise<void>;
123	  readonly cancelled: boolean;
124	}
125

