      async () => {
        await io.sleep(5);
        return "fast";
      },
      async () => {
        defer(() => cleaned.push("slow cleaned"));
        await io.sleep(1000);
        return "slow";
      },
    ]);
    expect(result).toBe("fast");
    expect(cleaned).toEqual(["slow cleaned"]);
  });

