  const handle = io
    .coroutine(async () => {
      await new Promise<void>(() => {});
    })
    .spawn({ cancelTimeout: 10 });

  const outcome = await Promise.race([
    handle.then(
      () => "settled",
      () => "settled",
    ),
    new Promise((r) => setTimeout(() => r("still pending"), 50)),
  ]);
  expect(outcome).toBe("still pending");

  handle.cancel(); // clean up: reaped at 10ms
  await caught(handle);
});

