import { afterEach, expect, jest, test } from "bun:test";
import { CancelledError, io, resetLogger, setLogger } from "@arche/concurrency";

afterEach(() => {
  (jest as any).useRealTimers?.();
  resetLogger();
});

test("async variant availability", () => {
  console.log("advanceTimersByTimeAsync:", typeof (jest as any).advanceTimersByTimeAsync);
  console.log("runAllTimersAsync:", typeof (jest as any).runAllTimersAsync);
  console.log("runOnlyPendingTimers:", typeof (jest as any).runOnlyPendingTimers);
});

test("io.sleep resolves under fake timers", async () => {
  (jest as any).useFakeTimers();
  let done = false;
  const handle = io
    .coroutine(async () => {
      await io.sleep(60_000); // would make the real test take a minute
      done = true;
      return "ok";
    })
    .spawn();

  const advance = (jest as any).advanceTimersByTimeAsync ?? (jest as any).advanceTimersByTime;
  await advance.call(jest, 60_000);
  expect(await handle).toBe("ok");
  expect(done).toBe(true);
});

test("zombie reaper fires under fake timers (default 5000ms budget, no real wait)", async () => {
  (jest as any).useFakeTimers();
  const warns: string[] = [];
  setLogger({
    debug: () => {},
    info: () => {},
    warn: (_m, f) => warns.push(String(f?.code)),
    error: () => {},
  });

  const handle = io
    .coroutine(async () => {
      await new Promise<void>(() => {}); // frozen
    })
    .spawn(); // DEFAULT cancelTimeout (5000ms) - unaffordable with real timers

  handle.cancel();
  const advance = (jest as any).advanceTimersByTimeAsync ?? (jest as any).advanceTimersByTime;
  await advance.call(jest, 5_000);

  let err: unknown;
  try {
    await handle;
  } catch (e) {
    err = e;
  }
  expect(err).toBeInstanceOf(CancelledError);
  expect(warns).toContain("coroutine_hung");
});

