test("is setImmediate faked? can it serve as a microtask flush?", async () => {
  (jest as any).useFakeTimers();
  let immediateRan = false;
  const p = new Promise<void>((r) =>
    setImmediate(() => {
      immediateRan = true;
      r();
    }),
  );
  // If setImmediate is mocked, this await would hang without an advance call.
  const raced = await Promise.race([p.then(() => "ran"), Promise.resolve().then(() => "pending")]);
  console.log("first race:", raced, "| immediateRan:", immediateRan);
  await p; // would hang forever if faked and never advanced
  console.log("setImmediate fired without advancing -> usable as flush");
  expect(immediateRan).toBe(true);
});

test("timer -> microtask -> timer chain: cancelGracefully with an async defer that sleeps", async () => {
  (jest as any).useFakeTimers();
  const flush = () => new Promise<void>((r) => setImmediate(r));
  const order: string[] = [];

  const handle = io
    .coroutine(async () => {
      defer(async () => {
        await io.sleep(20); // timer registered only AFTER cancel unwinds the body
        order.push("cleaned");
      });
      await io.sleep(60_000);
    })
    .spawn();

  const done = handle.cancelGracefully();
  await flush(); // let the abort propagate and the defer register its sleep timer
  (jest as any).advanceTimersByTime(20);
  await done;
  expect(order).toEqual(["cleaned"]);
  console.log("chain OK:", order);
});

