function stateOf(p: PromiseLike<unknown>): Promise<"settled" | "pending"> {
  return Promise.race([
    Promise.resolve(p).then(
      () => "settled" as const,
      () => "settled" as const,
    ),
    flush().then(() => "pending" as const),
  ]);
}

